sql:
SELECT T1.product_name, T2.subcategory_name
FROM products AS T1
INNER JOIN product_subcategories AS T2 ON T1.subcategory_id = T2.subcategory_id;

SELECT * 
FROM measurement_charts
WHERE chart_status = 'active';

external_knowledge:
- "blooming branches" metaphorically represent active subcategories as they are part of the product structure that is still in use and growing;
- "product garden" symbolizes the range of available products categorized and subcategorized within the product database;
- "flourishing" indicates that these branches (subcategories) have an active status;
- "average value of their blossoms" refers to the average price of products within each active subcategory, where "blossoms" represent the products.

sql:
SELECT size_id, international_size, us_size, size_status
FROM customer_sizes
WHERE subcategory_id = 1;

SELECT o.order_id, o.total
FROM orders o
JOIN order_items oi ON o.order_id = oi.order_id
WHERE oi.product_id IN (
    SELECT product_id FROM products WHERE price > (SELECT AVG(price) FROM products)
);

SELECT *
FROM product_subcategories
WHERE subcategory_status = 'active';
